SELECT emp_name, dept_name, position_name, email, phone
   FROM v_employee_full
   WHERE position_name = '부장' AND status = '재직';

SELECT emp_name, dept_name, TIMESTAMPDIFF(YEAR, birth_date, CURDATE()) AS age
   FROM v_employee_full
   WHERE status = '재직' AND TIMESTAMPDIFF(YEAR, birth_date, CURDATE()) BETWEEN 30 AND 40;

SELECT emp_name, dept_name, gross_salary, total_deduction, net_salary, salary_status
   FROM v_salary_summary
   WHERE salary_year = YEAR(CURDATE()) AND salary_month = MONTH(CURDATE());

SELECT emp_name, dept_name, salary_year, salary_month, net_salary, salary_status
   FROM v_salary_summary
   WHERE salary_status = '대기';

SELECT emp_name, national_pension, health_insurance, employment_insurance, income_tax, total_deduction
   FROM v_salary_summary
   WHERE salary_year = YEAR(CURDATE()) AND salary_month = MONTH(CURDATE());

SELECT COUNT(*) AS approved_count, SUM(ot_hours) AS total_ot_hours
   FROM overtime_request
   WHERE status = '승인' AND YEAR(ot_date) = YEAR(CURDATE()) AND MONTH(ot_date) = MONTH(CURDATE());

SELECT emp_name, dept_name, leave_type, start_date, end_date, days
   FROM v_leave_status
   WHERE leave_status = '대기';

SELECT emp_name, dept_name, start_date, end_date, days
   FROM v_leave_status
   WHERE leave_type = '병가' AND leave_year = YEAR(CURDATE()) AND leave_status = '승인';

SELECT emp_name, dept_name, total_score, grade
   FROM v_evaluation_result
   WHERE eval_year = 2024 AND eval_period = '하반기' AND grade = 'S';

SELECT v.emp_name, v.dept_name, v.position_name, v.eval_year, v.eval_period, v.total_score, v.grade
   FROM v_evaluation_result v
   WHERE v.position_name = '부장' AND v.grade = 'S' AND v.eval_status = '최종확정';

SELECT emp_id, emp_name, dept_name, position_name, emp_type, base_salary, hire_date, birth_date, gender, email, phone
   FROM v_employee_full
   WHERE status = '재직' AND emp_type = '정규직';
